// ServerInterface represents all server handlers.
type ServerInterface interface {
	// Authenticate a user and open a server-side session.
	// (POST /auth/login)
	Login(w http.ResponseWriter, r *http.Request)
	// Close the current server-side session.
	// (POST /auth/logout)
	Logout(w http.ResponseWriter, r *http.Request)
	// Return the identity of the current session.
	// (GET /auth/me)
	GetCurrentSession(w http.ResponseWriter, r *http.Request)
	// Converse with the LLM plane over a Server-Sent Events stream.
	// (POST /chat)
	Chat(w http.ResponseWriter, r *http.Request)
	// Connect the DK account for a marketplace account.
	// (POST /connector/connect)
	ConnectConnector(w http.ResponseWriter, r *http.Request)
	// Disconnect the DK account and purge stored tokens.
	// (POST /connector/disconnect)
	DisconnectConnector(w http.ResponseWriter, r *http.Request)
	// Refresh the DK access token and re-run capability probes.
	// (POST /connector/refresh)
	RefreshConnector(w http.ResponseWriter, r *http.Request)
	// Inspect connection and per-capability status.
	// (GET /connector/status)
	GetConnectorStatus(w http.ResponseWriter, r *http.Request, params GetConnectorStatusParams)
	// Re-fetch a stored cost-import preview batch.
	// (GET /cost/import)
	GetCostImportPreview(w http.ResponseWriter, r *http.Request, params GetCostImportPreviewParams)
	// Commit a confirmed cost-import preview.
	// (POST /cost/import/commit)
	CommitCostImport(w http.ResponseWriter, r *http.Request)
	// Build a CSV cost-import preview (no commit).
	// (POST /cost/import/preview)
	PreviewCostImport(w http.ResponseWriter, r *http.Request)
	// List the in-force cost-profile versions for a SKU at a time.
	// (GET /cost/profiles)
	ListCostProfiles(w http.ResponseWriter, r *http.Request, params ListCostProfilesParams)
	// Read a SKU's margin readiness.
	// (GET /cost/readiness)
	GetMarginReadiness(w http.ResponseWriter, r *http.Request, params GetMarginReadinessParams)
	// Record a single cost-component value.
	// (POST /cost/value)
	EnterSingleCost(w http.ResponseWriter, r *http.Request)
	// Get a single market event by id.
	// (GET /event)
	GetEvent(w http.ResponseWriter, r *http.Request, params GetEventParams)
	// List the account's open market events.
	// (GET /events)
	ListEvents(w http.ResponseWriter, r *http.Request, params ListEventsParams)
	// Record relevance feedback on a market event.
	// (POST /events/relevance)
	RecordEventRelevance(w http.ResponseWriter, r *http.Request)
	// Liveness probe with build identity.
	// (GET /healthz)
	GetHealthz(w http.ResponseWriter, r *http.Request)
	// Confirm a Needs Review candidate as the variant's active mapping.
	// (POST /identity/confirm)
	ConfirmIdentity(w http.ResponseWriter, r *http.Request)
	// Defer a Needs Review candidate, keeping it in the queue.
	// (POST /identity/defer)
	DeferIdentity(w http.ResponseWriter, r *http.Request)
	// List the Needs Review identity-mapping queue for an account.
	// (GET /identity/needs-review)
	ListNeedsReview(w http.ResponseWriter, r *http.Request, params ListNeedsReviewParams)
	// Reject a Needs Review candidate.
	// (POST /identity/reject)
	RejectIdentity(w http.ResponseWriter, r *http.Request)
	// Upload an extension (Route B) observation capture.
	// (POST /observation/capture)
	UploadCapture(w http.ResponseWriter, r *http.Request)
	// List append-only observation evidence for a target.
	// (GET /observation/observations)
	ListObservations(w http.ResponseWriter, r *http.Request, params ListObservationsParams)
	// List the account's derived current Observed Offers.
	// (GET /observation/observed-offers)
	ListObservedOffers(w http.ResponseWriter, r *http.Request, params ListObservedOffersParams)
	// List the account's observation targets.
	// (GET /observation/targets)
	ListObservationTargets(w http.ResponseWriter, r *http.Request, params ListObservationTargetsParams)
	// Simulate the contribution + six-stage policy engines (non-executable).
	// (POST /policy/simulate)
	SimulatePolicy(w http.ResponseWriter, r *http.Request)
	// Get the ranked Today feed for the account.
	// (GET /today)
	GetTodayFeed(w http.ResponseWriter, r *http.Request, params GetTodayFeedParams)
}

