// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Authenticate a user and open a server-side session.
	// (POST /auth/login)
	Login(ctx context.Context, request LoginRequestObject) (LoginResponseObject, error)
	// Close the current server-side session.
	// (POST /auth/logout)
	Logout(ctx context.Context, request LogoutRequestObject) (LogoutResponseObject, error)
	// Return the identity of the current session.
	// (GET /auth/me)
	GetCurrentSession(ctx context.Context, request GetCurrentSessionRequestObject) (GetCurrentSessionResponseObject, error)
	// Converse with the LLM plane over a Server-Sent Events stream.
	// (POST /chat)
	Chat(ctx context.Context, request ChatRequestObject) (ChatResponseObject, error)
	// Connect the DK account for a marketplace account.
	// (POST /connector/connect)
	ConnectConnector(ctx context.Context, request ConnectConnectorRequestObject) (ConnectConnectorResponseObject, error)
	// Disconnect the DK account and purge stored tokens.
	// (POST /connector/disconnect)
	DisconnectConnector(ctx context.Context, request DisconnectConnectorRequestObject) (DisconnectConnectorResponseObject, error)
	// Refresh the DK access token and re-run capability probes.
	// (POST /connector/refresh)
	RefreshConnector(ctx context.Context, request RefreshConnectorRequestObject) (RefreshConnectorResponseObject, error)
	// Inspect connection and per-capability status.
	// (GET /connector/status)
	GetConnectorStatus(ctx context.Context, request GetConnectorStatusRequestObject) (GetConnectorStatusResponseObject, error)
	// Re-fetch a stored cost-import preview batch.
	// (GET /cost/import)
	GetCostImportPreview(ctx context.Context, request GetCostImportPreviewRequestObject) (GetCostImportPreviewResponseObject, error)
	// Commit a confirmed cost-import preview.
	// (POST /cost/import/commit)
	CommitCostImport(ctx context.Context, request CommitCostImportRequestObject) (CommitCostImportResponseObject, error)
	// Build a CSV cost-import preview (no commit).
	// (POST /cost/import/preview)
	PreviewCostImport(ctx context.Context, request PreviewCostImportRequestObject) (PreviewCostImportResponseObject, error)
	// List the in-force cost-profile versions for a SKU at a time.
	// (GET /cost/profiles)
	ListCostProfiles(ctx context.Context, request ListCostProfilesRequestObject) (ListCostProfilesResponseObject, error)
	// Read a SKU's margin readiness.
	// (GET /cost/readiness)
	GetMarginReadiness(ctx context.Context, request GetMarginReadinessRequestObject) (GetMarginReadinessResponseObject, error)
	// Record a single cost-component value.
	// (POST /cost/value)
	EnterSingleCost(ctx context.Context, request EnterSingleCostRequestObject) (EnterSingleCostResponseObject, error)
	// Get a single market event by id.
	// (GET /event)
	GetEvent(ctx context.Context, request GetEventRequestObject) (GetEventResponseObject, error)
	// List the account's open market events.
	// (GET /events)
	ListEvents(ctx context.Context, request ListEventsRequestObject) (ListEventsResponseObject, error)
	// Record relevance feedback on a market event.
	// (POST /events/relevance)
	RecordEventRelevance(ctx context.Context, request RecordEventRelevanceRequestObject) (RecordEventRelevanceResponseObject, error)
	// Liveness probe with build identity.
	// (GET /healthz)
	GetHealthz(ctx context.Context, request GetHealthzRequestObject) (GetHealthzResponseObject, error)
	// Confirm a Needs Review candidate as the variant's active mapping.
	// (POST /identity/confirm)
	ConfirmIdentity(ctx context.Context, request ConfirmIdentityRequestObject) (ConfirmIdentityResponseObject, error)
	// Defer a Needs Review candidate, keeping it in the queue.
	// (POST /identity/defer)
	DeferIdentity(ctx context.Context, request DeferIdentityRequestObject) (DeferIdentityResponseObject, error)
	// List the Needs Review identity-mapping queue for an account.
	// (GET /identity/needs-review)
	ListNeedsReview(ctx context.Context, request ListNeedsReviewRequestObject) (ListNeedsReviewResponseObject, error)
	// Reject a Needs Review candidate.
	// (POST /identity/reject)
	RejectIdentity(ctx context.Context, request RejectIdentityRequestObject) (RejectIdentityResponseObject, error)
	// Upload an extension (Route B) observation capture.
	// (POST /observation/capture)
	UploadCapture(ctx context.Context, request UploadCaptureRequestObject) (UploadCaptureResponseObject, error)
	// List append-only observation evidence for a target.
	// (GET /observation/observations)
	ListObservations(ctx context.Context, request ListObservationsRequestObject) (ListObservationsResponseObject, error)
	// List the account's derived current Observed Offers.
	// (GET /observation/observed-offers)
	ListObservedOffers(ctx context.Context, request ListObservedOffersRequestObject) (ListObservedOffersResponseObject, error)
	// List the account's observation targets.
	// (GET /observation/targets)
	ListObservationTargets(ctx context.Context, request ListObservationTargetsRequestObject) (ListObservationTargetsResponseObject, error)
	// Simulate the contribution + six-stage policy engines (non-executable).
	// (POST /policy/simulate)
	SimulatePolicy(ctx context.Context, request SimulatePolicyRequestObject) (SimulatePolicyResponseObject, error)
	// Get the ranked Today feed for the account.
	// (GET /today)
	GetTodayFeed(ctx context.Context, request GetTodayFeedRequestObject) (GetTodayFeedResponseObject, error)
}

type StrictHandlerFunc func(ctx context.Context, w http.ResponseWriter, r *http.Request, request any) (any, error)
type StrictMiddlewareFunc func(f StrictHandlerFunc, operationID string) StrictHandlerFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

// Login operation middleware
func (sh *strictHandler) Login(w http.ResponseWriter, r *http.Request) {
	var request LoginRequestObject

	var body LoginJSONRequestBody
	if err := json.NewDecoder(r.Body).Decode(&body); err != nil {
		sh.options.RequestErrorHandlerFunc(w, r, fmt.Errorf("can't decode JSON body: %w", err))
		return
	}
	request.Body = &body

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.Login(ctx, request.(LoginRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "Login")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(LoginResponseObject); ok {
		if err := validResponse.VisitLoginResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}

